ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?amount_per_semester ?annual_cost WHERE {
  ?programs a :Programs .
  ?programs p:Amount_Per_Semester ?amount_per_semester .
  ?programs p:Annual_Cost ?annual_cost .
  ?programs p:name ?name_f .
  FILTER(STR(?name_f) = "Computer Science")
} }
  component: { SELECT ?annual_cost WHERE {
  ?programs a :Programs .
  ?programs p:Annual_Cost ?annual_cost .
  ?programs p:name ?name_f .
  FILTER(STR(?name_f) = "Computer Science")
} }
  component_2: { SELECT ?amount_per_semester WHERE {
  ?programs a :Programs .
  ?programs p:Amount_Per_Semester ?amount_per_semester .
  ?programs p:name ?name_f .
  FILTER(STR(?name_f) = "Computer Science")
} }
}
